import java.util.HashMap;
import java.util.Map;
import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.NamingException;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;

public class LdapSearch {
  public static Map<String, Object> searchUser(String username) throws NamingException {
    // Set up the LDAP connection
    DirContext ctx = new InitialDirContext();

    // Define the search filter
    String filter = "(&(objectClass=person)(sAMAccountName=" + username + "))";

    // Define the attributes to return
    String[] attrs = {"email", "fullname", "department"};

    // Perform the search
    NamingEnumeration<SearchResult> results = ctx.search("dc=example,dc=com", filter, attrs);

    // Create a map to store the user attributes
    Map<String, Object> userAttributes = new HashMap<>();

    // Iterate over the search results and add the attributes to the map
    while (results.hasMore()) {
      SearchResult result = results.next();
      Attributes attrs = result.getAttributes();
      for (Attribute attr : attrs.getAll()) {
        userAttributes.put(attr.getID(), attr.get());
      }
    }

    // Close the LDAP connection
    ctx.close();

    return userAttributes;
  }
}